def max_sum_of_subarrays(nums, k, mb):
    n = len(nums)
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    def get_sum(l, r):
        return prefix_sum[r + 1] - prefix_sum[l]

    dp = [[float('-inf')] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0

    for i in range(1, n + 1):
        for j in range(1, min(i // mb, k) + 1):
            for l in range(i - mb, i):
                if l >= 0:
                    dp[i][j] = max(dp[i][j], dp[l][j - 1] + get_sum(l, i - 1))

    return dp[n][k]

def max_sum_of_subarrays(nums, k, m):
    n = len(nums)
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    def get_subarray_sum(i, j):
        return prefix_sum[j + 1] - prefix_sum[i]

    memo = {}

    def dp(i, k):
        if (i, k) in memo:
            return memo[(i, k)]
        if k == 0:
            return 0
        if i >= n:
            return float('-inf')
        max_sum = float('-inf')
        for j in range(i, n):
            if j - i + 1 >= m:
                max_sum = max(max_sum, get_subarray_sum(i, j) + dp(j + m, k - 1))
        memo[(i, k)] = max_sum
        return max_sum

    return dp(0, k)

