def max_sum_subarrays(nums, k, m):
    n = len(nums)
    max_sum = float('-inf')
    for i in range(n):
        for j in range(i + m, n + 1):
            if j - i < m:
                continue
            subarray_sum = sum(nums[i:j])
            remaining_sum = max_sum_subarrays_helper(nums, k - 1, m, j + m)
            max_sum = max(max_sum, subarray_sum + remaining_sum)
    if k == 1:
        return max_sum
    else:
        return max(max_sum, max_sum_subarrays_helper(nums, k, m, 0))

def max_sum_subarrays_helper(nums, k, m, start):
    n = len(nums)
    if k == 0 or start >= n:
        return 0
    max_sum = float('-inf')
    for i in range(start, n):
        for j in range(i + m, n + 1):
            if j - i < m:
                continue
            subarray_sum = sum(nums[i:j])
            remaining_sum = max_sum_subarrays_helper(nums, k - 1, m, j + m)
            max_sum = max(max_sum, subarray_sum + remaining_sum)
    return max_sum

def max_sum_subarrays_dp(nums, k, m):
    n = len(nums)
    dp = {}
    def helper(i, k):
        if (i, k) in dp:
            return dp[(i, k)]
        if k == 0 or i >= n:
            return 0
        max_sum = float('-inf')
        for j in range(i, n):
            for end in range(j + m, n + 1):
                if end - j < m:
                    continue
                subarray_sum = sum(nums[j:end])
                remaining_sum = helper(end + m, k - 1)
                max_sum = max(max_sum, subarray_sum + remaining_sum)
        dp[(i, k)] = max_sum
        return max_sum
    return helper(0, k)

