    def max_subarray_sum(start, k, m):
        max_sum = float('-inf')
        for i in range(start, n - m + 1):
            total_sum = get_sum(i, i + m - 1)
            if k == 1:
                max_sum = max(max_sum, total_sum)
            else:
                max_sum = max(max_sum, total_sum + max_subarray_sum(i + m, k - 1, m))
